void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

void show_progress_done(void) { flushed_printf("\n"); }

template <int N, typename F>
double benchmark(F&& fn) {
  double best = fn();
  for (int i = 1; i < N; i++) {
    double v = fn();
    if (v < best) best = v;
  }
  return best;
}

template <typename T>
struct Ops {
  __device__ static inline T add(T a, T b) { return a + b; }
  __device__ static inline T mul(T a, T b) { return a * b; }
  __device__ static inline T mad(T a, T seed) { return add(mul(a, a), seed); }
  __device__ static inline T zero() { return (T)0; }
  __device__ static inline T minus_one() { return (T)-1; }
  __device__ static inline bool equal(T a, T b) { return a == b; }
};

template <>
struct Ops<int> {
  __device__ static inline int add(int a, int b) {
    return static_cast<int>(static_cast<unsigned int>(a) +
                            static_cast<unsigned int>(b));
  }
  __device__ static inline int mul(int a, int b) {
    return static_cast<int>(static_cast<unsigned int>(a) *
                            static_cast<unsigned int>(b));
  }
  __device__ static inline int mad(int a, int seed) { return add(mul(a, a), seed); }
  __device__ static inline int zero() { return 0; }
  __device__ static inline int minus_one() { return -1; }
  __device__ static inline bool equal(int a, int b) { return a == b; }
};

template <>
struct Ops<__half2> {
  __device__ static inline __half2 add(__half2 a, __half2 b) {
    float2 fa = __half22float2(a);
    float2 fb = __half22float2(b);
    return __floats2half2_rn(fa.x + fb.x, fa.y + fb.y);
  }
  __device__ static inline __half2 mul(__half2 a, __half2 b) {
    float2 fa = __half22float2(a);
    float2 fb = __half22float2(b);
    return __floats2half2_rn(fa.x * fb.x, fa.y * fb.y);
  }
  __device__ static inline __half2 mad(__half2 a, __half2 seed) {
    return add(mul(a, a), seed);
  }
  __device__ static inline __half2 zero() { return __float2half2_rn(0.0f); }
  __device__ static inline __half2 minus_one() { return __float2half2_rn(-1.0f); }
  __device__ static inline bool equal(__half2 a, __half2 b) {
    __half alo = __low2half(a);
    __half ahi = __high2half(a);
    __half blo = __low2half(b);
    __half bhi = __high2half(b);
    return __half_as_ushort(alo) == __half_as_ushort(blo) &&
           __half_as_ushort(ahi) == __half_as_ushort(bhi);
  }
};

template <typename T, int COMPUTE_ITERATIONS>
__global__ void benchmark_func(T seed, T* g_data) {
  const unsigned int blockSize = blockDim.x;
  const int grid_size = (int)(blockSize * gridDim.x);
  const int stride = grid_size;
  const int idx = (int)(blockIdx.x * blockDim.x + threadIdx.x);
  const int big_stride = (int)(gridDim.x * blockSize * kElementsPerWI);

  T tmps[kElementsPerWI];
#pragma unroll
  for (int k = 0; k < (int)kFusionDegree; k++) {
#pragma unroll
    for (int j = 0; j < (int)kElementsPerWI; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
#pragma unroll
      for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        tmps[j] = Ops<T>::mad(tmps[j], seed);
      }
    }

    T sum = Ops<T>::zero();
#pragma unroll
    for (int j = 0; j < (int)kElementsPerWI; j += 2) {
      sum = Ops<T>::add(sum, Ops<T>::mul(tmps[j], tmps[j + 1]));
    }

    if (Ops<T>::equal(sum, Ops<T>::minus_one())) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}

__global__ void warmup_func(short seed, short* g_data) {
  const int idx = (int)(blockIdx.x * blockDim.x + threadIdx.x);
  short tmp = g_data[idx];
  tmp = (short)(tmp * tmp + seed);
  if (tmp == (short)-1) g_data[idx] = tmp;
}

