template <typename T>
static void launch_benchmark_kernel(int ci,
                                    T seed,
                                    void* cbuffer,
                                    dim3 grid,
                                    dim3 block) {
  switch (ci) {
#define CASE_CI(CI) \
  case CI:          \
    benchmark_func<T, CI><<<grid, block>>>(seed, reinterpret_cast<T*>(cbuffer)); \
    break;
    FOR_EACH_COMPUTE_ITERATION(CASE_CI)
#undef CASE_CI
    default:
      break;
  }
}

template <typename F>
static double measure_cuda_event(F&& launch) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));
  CUDA_SAFE_CALL(cudaEventRecord(start, 0));
  launch();
  CUDA_SAFE_CALL(cudaGetLastError());
  CUDA_SAFE_CALL(cudaEventRecord(stop, 0));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));
  float elapsed_ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&elapsed_ms, start, stop));
  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));
  return (double)elapsed_ms;
}

static void runbench_warmup(void* cbuffer, long size) {
  const long reduced_grid_size = size / 256;
  const dim3 block((unsigned int)kWorkgroupSize);
  const dim3 grid((unsigned int)(reduced_grid_size / (long)kWorkgroupSize));
  const short seed = 1;
  warmup_func<<<grid, block>>>(seed, reinterpret_cast<short*>(cbuffer));
  CUDA_SAFE_CALL(cudaGetLastError());
}

static void runbench(const int compute_iterations_arr[],
                     unsigned int krn_idx,
                     void* cbuffer,
                     long size,
                     bool enable_dp,
                     bool enable_hp) {
  const long compute_grid_size = size / (long)kElementsPerWI / (long)kFusionDegree;
  const int current_compute_iterations = compute_iterations_arr[krn_idx];
  const long long computations =
      (kElementsPerWI * (long long)compute_grid_size +
       (2LL * kElementsPerWI * current_compute_iterations) *
           (long long)compute_grid_size) *
      (long long)kFusionDegree;
  const long long memoryoperations = size;

  const dim3 block((unsigned int)kWorkgroupSize);
  const dim3 grid((unsigned int)(compute_grid_size / (long)kWorkgroupSize));

  constexpr int total_bench_iterations = 3;

  double kernel_time_mad_sp = benchmark<total_bench_iterations>([&]() {
    const float seed_f = 1.0f;
    return measure_cuda_event([&]() {
      launch_benchmark_kernel<float>(current_compute_iterations, seed_f, cbuffer,
                                     grid, block);
    });
  });

  double kernel_time_mad_dp = benchmark<total_bench_iterations>([&]() {
    const double seed_d = 1.0;
    if (enable_dp) {
      return measure_cuda_event([&]() {
        launch_benchmark_kernel<double>(current_compute_iterations, seed_d, cbuffer,
                                        grid, block);
      });
    } else {
      return 0.0;
    }
  });

  double kernel_time_mad_hp = benchmark<total_bench_iterations>([&]() {
    const __half2 seed_h = __float2half2_rn(1.0f);
    if (enable_hp) {
      return measure_cuda_event([&]() {
        launch_benchmark_kernel<__half2>(current_compute_iterations, seed_h,
                                         cbuffer, grid, block);
      });
    } else {
      return 0.0;
    }
  });

  double kernel_time_mad_int = benchmark<total_bench_iterations>([&]() {
    const int seed_i = (int)1.0;
    return measure_cuda_event([&]() {
      launch_benchmark_kernel<int>(current_compute_iterations, seed_i, cbuffer,
                                   grid, block);
    });
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(__half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp *
          1000. / (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
  const char* benchtype = kBlockStrided ? "Workgroup" : "NDRange";
  printf("Workgroup size:         %d\n", (int)kWorkgroupSize);
  printf("Elements per workitem:  %d\n", (int)kElementsPerWI);
  printf("Workitem fusion degree: %d\n", (int)kFusionDegree);
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation =
      kHostAllocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n",
         kUseOSTimer ? "OS based" : "CL event based");

  cudaDeviceProp props = GetDeviceProperties();
  bool enable_dp = props.major > 1 || (props.major == 1 && props.minor >= 3);
  bool enable_hp = IsFP16Supported();

  if (!enable_dp)
    printf(
        "Warning:                Double precision computations are not "
        "supported\n");
  if (!enable_hp)
    printf(
        "Warning:                Half precision computations are not "
        "supported\n");

  if ((size_t)props.maxThreadsPerBlock < kWorkgroupSize) {
    fprintf(stderr, "Error: Unsupported workgroup size (%u).\n",
            (unsigned)kWorkgroupSize);
    exit(EXIT_FAILURE);
  }

  const long compute_grid_size = size / (long)kElementsPerWI / (long)kFusionDegree;
  const long reduced_grid_size = size / 256;
  if (compute_grid_size % (long)kWorkgroupSize != 0 ||
      reduced_grid_size % (long)kWorkgroupSize != 0) {
    fprintf(stderr, "Error: Unsupported vector size.\n");
    exit(EXIT_FAILURE);
  }

  void* c_buffer = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&c_buffer, (size_t)size * sizeof(double)));

  CUDA_SAFE_CALL(cudaMemset(c_buffer, 0, (size_t)size * sizeof(int)));

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  runbench_warmup(c_buffer, size);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  printf(
      "------------------------------------------------------------------------"
      "----- CSV data "
      "------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    runbench(compute_iterations, i, c_buffer, size, enable_dp, enable_hp);
  }

  printf(
      "------------------------------------------------------------------------"
      "------------------------------------------------------------------------"
      "--------------------\n");

  CUDA_SAFE_CALL(cudaMemcpy(c, c_buffer, (size_t)size * sizeof(double),
                            cudaMemcpyDeviceToHost));

  CUDA_SAFE_CALL(cudaFree(c_buffer));
}
